section("Edge cases: very large fields");
// ═══════════════════════════════════════════════════════════════════════════════

{
  const bigValue = "x".repeat(100_000);
  const csv = `col\n"${bigValue}"`;
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 1, "large field: one row");
  assertEqual((result.rows[0]["col"] as string).length, 100_000, "large field: length preserved");
}

{
  // Large number of columns
  const n = 500;
  const headers = Array.from({ length: n }, (_, i) => `c${i}`).join(",");
  const values = Array.from({ length: n }, (_, i) => String(i)).join(",");
  const csv = `${headers}\n${values}`;
  const result = parseCSV(csv);
  assertEqual(result.headers.length, n, "many columns: header count");
  assertEqual(result.rows[0]["c0"], 0, "many columns: first col");
  assertEqual(result.rows[0][`c${n - 1}`], n - 1, "many columns: last col");
}

