section("Edge cases: CRLF line endings");
// ═══════════════════════════════════════════════════════════════════════════════

{
  const csv = "name,age\r\nAlice,30\r\nBob,25\r\n";
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 2, "CRLF: two rows");
  assertEqual(result.rows[0]["name"], "Alice", "CRLF: first name");
  assertEqual(result.rows[1]["age"], 25, "CRLF: second age");
}

