section("Edge cases: newlines inside quoted fields");
// ═══════════════════════════════════════════════════════════════════════════════

{
  const csv = `id,text
1,"line one
line two"
2,"simple"`;

  const result = parseCSV(csv);
  assertEqual(result.rows.length, 2, "quoted newline: two rows");
  assertEqual(result.rows[0]["text"], "line one\nline two", "quoted newline: field preserved");
  assertEqual(result.rows[1]["text"], "simple", "quoted newline: next row OK");
}

