section("Edge cases: trailing delimiter");
// ═══════════════════════════════════════════════════════════════════════════════

{
  const csv = `a,b,c
1,2,
4,,6`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["c"], null, "trailing comma → empty → null");
  assertEqual(result.rows[1]["b"], null, "middle empty field → null");
  assertEqual(result.rows[1]["c"], 6, "field after empty is fine");
}

