section("Edge cases: spaces around fields");
// ═══════════════════════════════════════════════════════════════════════════════

{
  const csv = `a,b
 hello , world `;
  const result = parseCSV(csv);
  // Unquoted fields preserve spaces (only headers are trimmed)
  assertEqual(result.rows[0]["a"], " hello ", "spaces in unquoted field preserved");
  assertEqual(result.rows[0]["b"], " world ", "trailing spaces preserved");
}

