section("Combination: filter + aggregation");
// ═══════════════════════════════════════════════════════════════════════════════

{
  const csv = `dept,name,salary
Engineering,Alice,100000
Marketing,Bob,80000
Engineering,Charlie,120000
Marketing,Diana,90000
Engineering,Eve,110000`;

  const result = parseCSV(csv);

  // Use filter then manually sum
  const engRows = result.filter((r) => r["dept"] === "Engineering");
  assertEqual(engRows.length, 3, "combo: filter engineers");

  // Use groupBy to verify department totals
  const groups = result.groupBy("dept");
  const engSalaries = groups.get("Engineering")!;
  const engTotal = engSalaries.reduce((s, r) => s + (r["salary"] as number), 0);
  assertEqual(engTotal, 330000, "combo: engineering salary total");

  // Overall aggregations
  assertEqual(result.sum("salary"), 500000, "combo: total salary");
  assertEqual(result.average("salary"), 100000, "combo: average salary");
}

