// ─── Types ───────────────────────────────────────────────────────────────────

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
  coerceTypes?: boolean;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Record<string, unknown>[]>;
}

// ─── Field-level parser (handles quoting / escaping) ─────────────────────────

function parseFields(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let i = 0;
  const len = line.length;

  while (i <= len) {
    if (i === len) {
      // Trailing delimiter produced an empty trailing field
      // (only when previous char was a delimiter)
      if (fields.length > 0 && line[len - 1] === delimiter) {
        fields.push("");
      }
      break;
    }

    if (line[i] === quote) {
      // ── Quoted field ──────────────────────────────────────────────────
      i++; // skip opening quote
      let value = "";
      let closed = false;

      while (i < len) {
        if (line[i] === quote) {
          // Peek next char – escaped quote or closing quote?
          if (i + 1 < len && line[i + 1] === quote) {
            value += quote; // escaped quote → literal
            i += 2;
          } else {
            // Closing quote
            i++; // skip closing quote
            closed = true;
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }

      if (!closed) {
        // Unterminated quote – return what we have; caller will flag error
        // Push the value collected so far
        fields.push(value);
        break;
      }

      fields.push(value);

      // After closing quote we expect delimiter or end-of-line
      if (i < len) {
        if (line[i] === delimiter) {
          i++; // consume delimiter
          // If delimiter is at end of line, push trailing empty field
          if (i === len) {
            fields.push("");
          }
        } else {
          // Garbage after closing quote – skip to next delimiter
          while (i < len && line[i] !== delimiter) i++;
          if (i < len) i++; // skip delimiter
          if (i === len && line[i - 1] === delimiter) {
            fields.push("");
          }
        }
      }
    } else {
      // ── Unquoted field ────────────────────────────────────────────────
      let value = "";
      while (i < len && line[i] !== delimiter) {
        value += line[i];
        i++;
      }
      fields.push(value);

      if (i < len) {
        i++; // consume delimiter
        // Trailing delimiter → empty trailing field
        if (i === len) {
          fields.push("");
        }
      }
    }
  }

  return fields;
}

// ─── Type coercion ───────────────────────────────────────────────────────────

function coerce(value: string): unknown {
  // Null / empty
  if (value === "" || value === "null" || value === "NULL") {
    return null;
  }

  // Boolean
  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // Number – must be a valid finite number and not just whitespace
  if (value.trim() !== "") {
    const num = Number(value);
    if (!isNaN(num) && isFinite(num)) {
      return num;
    }
  }

  return value;
}

// ─── Line splitting (respects quoted fields spanning lines) ──────────────────

function splitLines(
  input: string,
  lineSeparator: string | undefined,
  quote: string
): string[] {
  // If a custom line separator is provided AND there are no quoted fields that
  // might contain that separator we can do a simple split.  But to be safe
  // with quoted fields that contain newlines we always use the state-machine
  // approach when quote characters are present.

  const sep = lineSeparator ?? "\n";
  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < input.length) {
    const ch = input[i];

    if (inQuotes) {
      if (ch === quote) {
        if (i + 1 < input.length && input[i + 1] === quote) {
          current += ch + input[i + 1];
          i += 2;
          continue;
        } else {
          inQuotes = false;
          current += ch;
          i++;
          continue;
        }
      }
      current += ch;
      i++;
    } else {
      if (ch === quote) {
        inQuotes = true;
        current += ch;
        i++;
      } else if (input.substring(i, i + sep.length) === sep) {
        lines.push(current);
        current = "";
        i += sep.length;
      } else {
        current += ch;
        i++;
      }
    }
  }

  // Push remaining content
  if (current.length > 0 || lines.length > 0) {
    lines.push(current);
  }

  return lines;
}

// ─── Main entry point ────────────────────────────────────────────────────────

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator; // undefined → auto (\n, \r\n)
  const shouldCoerce = options?.coerceTypes !== false; // default true

  // Normalise \r\n → \n when no explicit lineSeparator
  let normalised = input;
  if (!lineSeparator) {
    normalised = input.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
  }

  const lines = splitLines(normalised, lineSeparator, quote);

  // Strip trailing empty lines
  while (lines.length > 0 && lines[lines.length - 1].trim() === "") {
    lines.pop();
  }

  if (lines.length === 0) {
    return buildResult([], [], []);
  }

  // ── Headers ────────────────────────────────────────────────────────────
  const headers = parseFields(lines[0], delimiter, quote).map((h) => h.trim());

  // ── Data rows ──────────────────────────────────────────────────────────
  const rows: Record<string, unknown>[] = [];
  const errors: CSVError[] = [];

  for (let idx = 1; idx < lines.length; idx++) {
    const line = lines[idx];

    // Skip completely blank lines
    if (line.trim() === "") continue;

    try {
      const fields = parseFields(line, delimiter, quote);

      if (fields.length !== headers.length) {
        errors.push({
          row: idx + 1, // 1-based, header is row 1
          message: `Expected ${headers.length} fields but got ${fields.length}`,
        });
        // Still try to build a partial row
      }

      const row: Record<string, unknown> = {};
      for (let c = 0; c < headers.length; c++) {
        const raw = c < fields.length ? fields[c] : "";
        row[headers[c]] = shouldCoerce ? coerce(raw) : raw;
      }
      rows.push(row);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err);
      errors.push({ row: idx + 1, message: `Parse error: ${msg}` });
    }
  }

  return buildResult(rows, headers, errors);
}

// ─── Result builder (attaches helper methods) ────────────────────────────────

function buildResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean) {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number" && !isNaN(v)) {
          total += v;
        }
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number" && !isNaN(v)) {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };
}

import { parseCSV, CSVResult } from "./csv-parser";

// ─── Tiny assertion helpers ──────────────────────────────────────────────────

let passed = 0;
let failed = 0;
const failures: string[] = [];

function assert(condition: boolean, message: string): void {
  if (!condition) {
    failed++;
    failures.push(message);
    console.error(`  ✗ ${message}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function assertEqual(actual: unknown, expected: unknown, message: string): void {
  if (actual !== expected) {
    failed++;
    const detail = `${message} — expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`;
    failures.push(detail);
    console.error(`  ✗ ${detail}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, message: string): void {
  const a = JSON.stringify(actual);
  const b = JSON.stringify(expected);
  if (a !== b) {
    failed++;
    const detail = `${message}\n      expected: ${b}\n      actual:   ${a}`;
    failures.push(detail);
    console.error(`  ✗ ${detail}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function section(title: string): void {
  console.log(`\n══ ${title} ══`);
}

// ─── Tests ───────────────────────────────────────────────────────────────────

// ═══════════════════════════════════════════════════════════════════════════════
section("Basic parsing");
// ═══════════════════════════════════════════════════════════════════════════════

{
  const csv = `name,age,city
Alice,30,New York
Bob,25,London
Charlie,35,Paris`;

  const result = parseCSV(csv);

  assertDeepEqual(result.headers, ["name", "age", "city"], "headers parsed correctly");
  assertEqual(result.rows.length, 3, "three rows parsed");
  assertEqual(result.errors.length, 0, "no errors");

  assertEqual(result.rows[0]["name"], "Alice", "first row name");
  assertEqual(result.rows[0]["age"], 30, "first row age is numeric");
  assertEqual(result.rows[0]["city"], "New York", "first row city");

  assertEqual(result.rows[1]["name"], "Bob", "second row name");
  assertEqual(result.rows[1]["age"], 25, "second row age");
  assertEqual(result.rows[1]["city"], "London", "second row city");

  assertEqual(result.rows[2]["name"], "Charlie", "third row name");
  assertEqual(result.rows[2]["age"], 35, "third row age");
  assertEqual(result.rows[2]["city"], "Paris", "third row city");
}

// ═══════════════════════════════════════════════════════════════════════════════
section("Quoted fields with commas");
// ═══════════════════════════════════════════════════════════════════════════════

{
  const csv = `name,address,age
"Smith, John","123 Main St, Apt 4",42
"Doe, Jane","456 Oak Ave",28`;

  const result = parseCSV(csv);

  assertEqual(result.errors.length, 0, "no errors with quoted fields");
  assertEqual(result.rows.length, 2, "two rows");
  assertEqual(result.rows[0]["name"], "Smith, John", "quoted name with comma");
  assertEqual(result.rows[0]["address"], "123 Main St, Apt 4", "quoted address with comma");
  assertEqual(result.rows[0]["age"], 42, "age coerced to number");
  assertEqual(result.rows[1]["name"], "Doe, Jane", "second quoted name");
}

// ═══════════════════════════════════════════════════════════════════════════════
section("Escaped quotes inside quoted fields");
// ═══════════════════════════════════════════════════════════════════════════════

{
  const csv = `title,description
"Hello","She said ""Hello, World!""."
"Test","A ""quoted"" word"`;

  const result = parseCSV(csv);

  assertEqual(result.errors.length, 0, "no errors with escaped quotes");
  assertEqual(result.rows[0]["description"], 'She said "Hello, World!".', "escaped quotes resolved");
  assertEqual(result.rows[1]["description"], 'A "quoted" word', "mid-field escaped quotes");
}

{
  // Consecutive escaped quotes
  const csv = `col
"He said """"""yes"""""""`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["col"], 'He said """yes"""', "multiple consecutive escaped quotes");
}

// ═══════════════════════════════════════════════════════════════════════════════
section("Custom delimiters");
// ═══════════════════════════════════════════════════════════════════════════════

{
  // Tab delimiter
  const csv = "name\tage\tactive\nAlice\t30\ttrue\nBob\t25\tfalse";
  const result = parseCSV(csv, { delimiter: "\t" });

  assertEqual(result.headers[0], "name", "tab delimited header 1");
  assertEqual(result.headers[1], "age", "tab delimited header 2");
  assertEqual(result.rows[0]["name"], "Alice", "tab delimited value");
  assertEqual(result.rows[0]["age"], 30, "tab delimited number");
  assertEqual(result.rows[0]["active"], true, "tab delimited boolean");
}

{
  // Semicolon delimiter
  const csv = "a;b;c\n1;2;3\n4;5;6";
