// ─── Field-level parser (handles quoting / escaping) ─────────────────────────

function parseFields(line, delimiter, quote) {
  const fields = [];
  let i = 0;
  const len = line.length;

  while (i <= len) {
    if (i === len) {
      if (fields.length > 0 && line[len - 1] === delimiter) {
        fields.push("");
      }
      break;
    }

    if (line[i] === quote) {
      i++;
      let value = "";
      let closed = false;

      while (i < len) {
        if (line[i] === quote) {
          if (i + 1 < len && line[i + 1] === quote) {
            value += quote;
            i += 2;
          } else {
            i++;
            closed = true;
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }

      if (!closed) {
        fields.push(value);
        break;
      }

      fields.push(value);

      if (i < len) {
        if (line[i] === delimiter) {
          i++;
          if (i === len) {
            fields.push("");
          }
        } else {
          while (i < len && line[i] !== delimiter) i++;
          if (i < len) i++;
          if (i === len && line[i - 1] === delimiter) {
            fields.push("");
          }
        }
      }
    } else {
      let value = "";
      while (i < len && line[i] !== delimiter) {
        value += line[i];
        i++;
      }
      fields.push(value);

      if (i < len) {
        i++;
        if (i === len) {
          fields.push("");
        }
      }
    }
  }

  return fields;
}

