        current += ch;
        i++;
      } else if (input.substring(i, i + sep.length) === sep) {
        lines.push(current);
        current = "";
        i += sep.length;
      } else {
        current += ch;
        i++;
      }
    }
  }

  if (current.length > 0 || lines.length > 0) {
    lines.push(current);
  }

  return lines;
}

// ─── Main entry point ────────────────────────────────────────────────────────

function parseCSV(input, options) {
  const delimiter = (options && options.delimiter) || ",";
  const quote = (options && options.quote) || '"';
  const lineSeparator = options && options.lineSeparator;
  const shouldCoerce = !(options && options.coerceTypes === false);

  let normalised = input;
  if (!lineSeparator) {
    normalised = input.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
  }

  const lines = splitLines(normalised, lineSeparator, quote);

  while (lines.length > 0 && lines[lines.length - 1].trim() === "") {
    lines.pop();
  }

  if (lines.length === 0) {
    return buildResult([], [], []);
  }

  const headers = parseFields(lines[0], delimiter, quote).map(function(h) { return h.trim(); });

  const rows = [];
  const errors = [];

  for (let idx = 1; idx < lines.length; idx++) {
    const line = lines[idx];

    if (line.trim() === "") continue;

    try {
      const fields = parseFields(line, delimiter, quote);

      if (fields.length !== headers.length) {
        errors.push({
          row: idx + 1,
          message: "Expected " + headers.length + " fields but got " + fields.length,
        });
      }

      const row = {};
      for (let c = 0; c < headers.length; c++) {
        const raw = c < fields.length ? fields[c] : "";
        row[headers[c]] = shouldCoerce ? coerce(raw) : raw;
      }
      rows.push(row);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      errors.push({ row: idx + 1, message: "Parse error: " + msg });
    }
  }

  return buildResult(rows, headers, errors);
}

// ─── Result builder ──────────────────────────────────────────────────────────

function buildResult(rows, headers, errors) {
  return {
    rows: rows,
    headers: headers,
    errors: errors,

    filter: function(predicate) {
      return rows.filter(predicate);
    },

    sum: function(column) {
      let total = 0;
      for (let i = 0; i < rows.length; i++) {
        const v = rows[i][column];
        if (typeof v === "number" && !isNaN(v)) {
          total += v;
        }
      }
      return total;
    },

    average: function(column) {
      let total = 0;
      let count = 0;
      for (let i = 0; i < rows.length; i++) {
        const v = rows[i][column];
        if (typeof v === "number" && !isNaN(v)) {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count: function() {
      return rows.length;
    },

    groupBy: function(column) {
      const map = new Map();
      for (let i = 0; i < rows.length; i++) {
        const key = rows[i][column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(rows[i]);
      }
      return map;
    },
  };
}

// Export for test
if (typeof module !== "undefined") {
  module.exports = { parseCSV };
}

var parseCSV = require("./csv-parser.js").parseCSV;

// ─── Tiny assertion helpers ──────────────────────────────────────────────────

var passed = 0;
var failed = 0;
var failures = [];

function assert(condition, message) {
  if (!condition) {
    failed++;
    failures.push(message);
    console.error("  ✗ " + message);
  } else {
    passed++;
    console.log("  ✓ " + message);
  }
}

function assertEqual(actual, expected, message) {
  if (actual !== expected) {
    failed++;
    var detail = message + " — expected " + JSON.stringify(expected) + ", got " + JSON.stringify(actual);
    failures.push(detail);
    console.error("  ✗ " + detail);
  } else {
    passed++;
    console.log("  ✓ " + message);
  }
}

function assertDeepEqual(actual, expected, message) {
  var a = JSON.stringify(actual);
  var b = JSON.stringify(expected);
  if (a !== b) {
    failed++;
    var detail = message + "\n      expected: " + b + "\n      actual:   " + a;
    failures.push(detail);
    console.error("  ✗ " + detail);
  } else {
    passed++;
    console.log("  ✓ " + message);
  }
}

function section(title) {
  console.log("\n══ " + title + " ══");
}

