section("Type coercion");
// ═══════════════════════════════════════════════════════════════════════════════

(function() {
  var csv = "int,float,neg,negfloat,bool_t,bool_f,bool_T,null1,null2,null3,str\n42,3.14,-7,-2.5,true,false,TRUE,null,NULL,,hello";

  var result = parseCSV(csv);

  assertEqual(result.rows[0]["int"], 42, "integer coercion");
  assertEqual(typeof result.rows[0]["int"], "number", "integer is number type");

  assertEqual(result.rows[0]["float"], 3.14, "float coercion");
  assertEqual(typeof result.rows[0]["float"], "number", "float is number type");

  assertEqual(result.rows[0]["neg"], -7, "negative integer");
  assertEqual(result.rows[0]["negfloat"], -2.5, "negative float");

  assertEqual(result.rows[0]["bool_t"], true, "true coercion");
  assertEqual(typeof result.rows[0]["bool_t"], "boolean", "true is boolean type");

  assertEqual(result.rows[0]["bool_f"], false, "false coercion");
  assertEqual(typeof result.rows[0]["bool_f"], "boolean", "false is boolean type");

  assertEqual(result.rows[0]["bool_T"], true, "TRUE (uppercase) coercion");

  assertEqual(result.rows[0]["null1"], null, "null string → null");
  assertEqual(result.rows[0]["null2"], null, "NULL string → null");
  assertEqual(result.rows[0]["null3"], null, "empty string → null");

  assertEqual(result.rows[0]["str"], "hello", "plain string stays string");
  assertEqual(typeof result.rows[0]["str"], "string", "string type preserved");
})();

(function() {
  // Zero and special number forms
  var csv = "a,b,c,d\n0,0.0,1e3,0xFF";
  var result = parseCSV(csv);

  assertEqual(result.rows[0]["a"], 0, "zero coercion");
  assertEqual(result.rows[0]["b"], 0, "0.0 coercion");
  assertEqual(result.rows[0]["c"], 1000, "scientific notation");
  assertEqual(result.rows[0]["d"], 255, "hex notation");
})();

(function() {
  // coerceTypes = false disables coercion
  var csv = "a,b\n42,true";
  var result = parseCSV(csv, { coerceTypes: false });

  assertEqual(result.rows[0]["a"], "42", "no coercion: number stays string");
  assertEqual(typeof result.rows[0]["a"], "string", "no coercion: type is string");
  assertEqual(result.rows[0]["b"], "true", "no coercion: boolean stays string");
})();

