  var engSalaries = groups.get("Engineering");
  var engTotal = engSalaries.reduce(function(s, r) { return s + r["salary"]; }, 0);
  assertEqual(engTotal, 330000, "combo: engineering salary total");

  assertEqual(result.sum("salary"), 500000, "combo: total salary");
  assertEqual(result.average("salary"), 100000, "combo: average salary");
})();

// ═══════════════════════════════════════════════════════════════════════════════
section("Edge cases: quoted empty fields and quoted numbers");
// ═══════════════════════════════════════════════════════════════════════════════

(function() {
  var csv = 'a,b\n"",""\n"42","true"';
  var result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], null, "quoted empty → null");
  assertEqual(result.rows[1]["a"], 42, "quoted number still coerced");
  assertEqual(result.rows[1]["b"], true, "quoted boolean still coerced");
})();

// ═══════════════════════════════════════════════════════════════════════════════
section("Edge cases: headers with special characters");
// ═══════════════════════════════════════════════════════════════════════════════

(function() {
  var csv = '"first name","last name","age (years)"\nJohn,Doe,30';
  var result = parseCSV(csv);
  assertDeepEqual(result.headers, ["first name", "last name", "age (years)"], "headers with spaces/parens");
  assertEqual(result.rows[0]["first name"], "John", "access by special header");
  assertEqual(result.rows[0]["age (years)"], 30, "access by paren header");
})();

// ═══════════════════════════════════════════════════════════════════════════════
section("Large dataset");
// ═══════════════════════════════════════════════════════════════════════════════

(function() {
  var lines = ["id,value"];
  for (var i = 0; i < 10000; i++) {
    lines.push(i + "," + (i * 2));
  }
  var csv = lines.join("\n");
  var result = parseCSV(csv);

  assertEqual(result.count(), 10000, "large dataset: 10k rows");
  assertEqual(result.rows[0]["id"], 0, "large dataset: first id");
  assertEqual(result.rows[9999]["id"], 9999, "large dataset: last id");
  assertEqual(result.sum("value"), 2 * (9999 * 10000) / 2, "large dataset: sum correct");
  assertEqual(result.average("id"), 4999.5, "large dataset: average correct");
  assertEqual(result.errors.length, 0, "large dataset: no errors");
})();

// ═══════════════════════════════════════════════════════════════════════════════
section("Mixed quoting styles on same row");
// ═══════════════════════════════════════════════════════════════════════════════

(function() {
  var csv = 'a,b,c\nunquoted,"quoted",123';
  var result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], "unquoted", "mixed: unquoted field");
  assertEqual(result.rows[0]["b"], "quoted", "mixed: quoted field");
  assertEqual(result.rows[0]["c"], 123, "mixed: number field");
})();

// ═══════════════════════════════════════════════════════════════════════════════
section("Boolean case insensitivity");
// ═══════════════════════════════════════════════════════════════════════════════

(function() {
  var csv = "val\ntrue\nTRUE\nTrue\nTrUe\nfalse\nFALSE\nFalse\nFaLsE";

  var result = parseCSV(csv);
  for (var i = 0; i < 4; i++) {
    assertEqual(result.rows[i]["val"], true, "bool case " + i + ": true");
  }
  for (var i = 4; i < 8; i++) {
    assertEqual(result.rows[i]["val"], false, "bool case " + i + ": false");
  }
})();

// ═══════════════════════════════════════════════════════════════════════════════
section("Only headers, no trailing newline");
// ═══════════════════════════════════════════════════════════════════════════════

(function() {
  var result = parseCSV("a,b,c");
  assertDeepEqual(result.headers, ["a", "b", "c"], "headers-only no newline: headers");
  assertEqual(result.rows.length, 0, "headers-only no newline: no rows");
})();

// ═══════════════════════════════════════════════════════════════════════════════
// Summary
// ═══════════════════════════════════════════════════════════════════════════════

console.log("\n" + "════════════════════════════════════════════════════════════");
console.log("Results: " + passed + " passed, " + failed + " failed, " + (passed + failed) + " total");
if (failed > 0) {
  console.log("\nFailures:");
  for (var i = 0; i < failures.length; i++) {
    console.log("  " + (i + 1) + ". " + failures[i]);
